#include <signal.h>
#include <stdio.h>
#include <unistd.h>

/* Using signal() -- unreliable on System V */
void old_handler(int sig) {
    /* On System V, disposition is now SIG_DFL!
       Another SIGINT here would kill the process */
    signal(sig, old_handler);  /* try to reinstall (race!) */
    printf("Caught signal %d (unreliable)\n", sig);
}

/* Using sigaction() -- reliable */
void safe_handler(int sig) {
    /* Signal is blocked during this handler (no race) */
    /* Disposition is NOT reset */
    const char msg[] = "Caught signal (reliable)\n";
    write(STDOUT_FILENO, msg, sizeof(msg) - 1);  /* async-signal-safe */
}

int main(void) {
    /* Unreliable way (avoid in production) */
    signal(SIGINT, old_handler);

    /* Reliable way (always prefer this) */
    struct sigaction sa;
    sa.sa_handler = safe_handler;
    sigemptyset(&sa.sa_mask);
    sa.sa_flags = SA_RESTART;  /* restart interrupted syscalls */
    if (sigaction(SIGINT, &sa, NULL) == -1) {
        perror("sigaction");
        return 1;
    }

    printf("Press Ctrl+C to test (pid=%d)\n", getpid());
    pause();  /* wait for signal */
    printf("Returned from pause\n");

    return 0;
}

