void info_handler(int sig, siginfo_t *info, void *ucontext) {
    (void)ucontext;
    char buf[128];
    int n = snprintf(buf, sizeof(buf),
                     "Signal %d from PID %d, UID %d\n",
                     sig, info->si_pid, info->si_uid);
