    /* SA_SIGINFO handler for detailed signal info */
    struct sigaction sa2;
    memset(&sa2, 0, sizeof(sa2));
    sa2.sa_sigaction = info_handler;
    sigemptyset(&sa2.sa_mask);
    sa2.sa_flags = SA_SIGINFO | SA_RESTART;
    sigaction(SIGUSR1, &sa2, NULL);

    printf("pid=%d, send SIGINT or SIGUSR1\n", getpid());

    while (!got_sigint) {
