int main(void) {
    struct sigaction sa;
    memset(&sa, 0, sizeof(sa));
    sa.sa_handler = handler;
    sigemptyset(&sa.sa_mask);
    sa.sa_flags = SA_RESTART;

    sigaction(SIGINT, &sa, NULL);   /* Ctrl+C */
    sigaction(SIGTERM, &sa, NULL);  /* kill <pid> */
    sigaction(SIGHUP, &sa, NULL);   /* terminal hangup */
    sigaction(SIGUSR1, &sa, NULL);  /* user-defined */

    /* Ignore SIGPIPE (common in servers) */
    signal(SIGPIPE, SIG_IGN);

    /* Cannot catch SIGKILL or SIGSTOP */
    if (sigaction(SIGKILL, &sa, NULL) == -1)
        perror("sigaction SIGKILL");  /* EINVAL */

    printf("pid=%d, waiting for signals...\n", getpid());
    for (;;) pause();

    return 0;
}

