    /* Custom handler */
    struct sigaction sa;
    memset(&sa, 0, sizeof(sa));
    sa.sa_handler = my_handler;
    sigemptyset(&sa.sa_mask);
    sa.sa_flags = 0;
    sigaction(SIGINT, &sa, NULL);

    /* Query current disposition without changing it */
    struct sigaction old;
    sigaction(SIGUSR1, NULL, &old);
    if (old.sa_handler == SIG_DFL)
        printf("SIGUSR1: default action\n");
    else if (old.sa_handler == SIG_IGN)
        printf("SIGUSR1: ignored\n");
    else
        printf("SIGUSR1: custom handler\n");

    /* Respect inherited SIG_IGN (shell backgrounded us) */
    sigaction(SIGINT, NULL, &old);
    if (old.sa_handler != SIG_IGN) {
        sa.sa_handler = my_handler;
        sigaction(SIGINT, &sa, NULL);
    }
    /* If shell set SIG_IGN, we respect it */

    printf("pid=%d\n", getpid());
    pause();
    return 0;
}

