int main(void) {
    /* Send signal to self */
    printf("Raising SIGUSR1 to self\n");
    signal(SIGUSR1, SIG_IGN);  /* ignore so we don't die */
    raise(SIGUSR1);  /* equivalent to kill(getpid(), SIGUSR1) */

    /* Check if a process exists */
    pid_t test_pid = 99999;
    if (kill(test_pid, 0) == -1) {
        if (errno == ESRCH)
            printf("Process %d does not exist\n", test_pid);
        else if (errno == EPERM)
            printf("Process %d exists but no permission\n", test_pid);
    }

    /* Send to child process */
    pid_t child = fork();
    if (child == 0) {
        signal(SIGUSR1, SIG_DFL);  /* default: terminate */
        pause();  /* wait for signal */
        _exit(0);
    }

    sleep(1);
    printf("Sending SIGUSR1 to child %d\n", child);
    kill(child, SIGUSR1);  /* terminate child */

    int status;
    waitpid(child, &status, 0);
    if (WIFSIGNALED(status))
        printf("Child killed by signal %d\n", WTERMSIG(status));

    return 0;
}

