static volatile sig_atomic_t child_count = 0;

void sigchld_handler(int sig) {
    (void)sig;
    int saved_errno = errno;
    pid_t pid;
    int status;

    /* Reap ALL available children */
    while ((pid = waitpid(-1, &status, WNOHANG)) > 0) {
        child_count--;
        /* write is async-signal-safe; printf is NOT */
        char buf[64];
        int n;
        if (WIFEXITED(status))
            n = snprintf(buf, sizeof(buf), "Child %d exited (%d)\n",
                         pid, WEXITSTATUS(status));
        else
            n = snprintf(buf, sizeof(buf), "Child %d killed\n", pid);
        write(STDOUT_FILENO, buf, (size_t)n);
    }

    errno = saved_errno;
}

int main(void) {
    struct sigaction sa;
    memset(&sa, 0, sizeof(sa));
    sa.sa_handler = sigchld_handler;
    sigemptyset(&sa.sa_mask);
    sa.sa_flags = SA_RESTART | SA_NOCLDSTOP;
    sigaction(SIGCHLD, &sa, NULL);

    /* Fork 5 children */
    for (int i = 0; i < 5; i++) {
        if (fork() == 0) {
            sleep((unsigned)i);  /* stagger exits */
            _exit(i);
        }
        child_count++;
    }

    /* Parent: do work while children run */
    while (child_count > 0) {
        pause();  /* wait for signals */
    }

    printf("All children reaped\n");
    return 0;
}

