#include <signal.h>
#include <pthread.h>
#include <stdio.h>
#include <unistd.h>
#include <string.h>

static volatile sig_atomic_t running = 1;

void *signal_thread(void *arg) {
    sigset_t *set = (sigset_t *)arg;
    int sig;

    while (running) {
        /* Synchronously wait for signals */
        int ret = sigwait(set, &sig);
        if (ret != 0) continue;

        switch (sig) {
            case SIGINT:
                printf("Signal thread: SIGINT received, shutting down\n");
                running = 0;
                break;
            case SIGHUP:
                printf("Signal thread: SIGHUP received, reloading config\n");
                break;
            default:
                printf("Signal thread: signal %d received\n", sig);
                break;
        }
    }
    return NULL;
}

void *worker_thread(void *arg) {
    int id = *(int *)arg;
    while (running) {
        printf("Worker %d doing work...\n", id);
        sleep(2);
    }
    printf("Worker %d exiting\n", id);
    return NULL;
}

int main(void) {
    /* Block all signals in main thread */
    sigset_t block_all;
    sigfillset(&block_all);
    pthread_sigmask(SIG_BLOCK, &block_all, NULL);

    /* Signals we want to handle */
    sigset_t handle_set;
    sigemptyset(&handle_set);
    sigaddset(&handle_set, SIGINT);
    sigaddset(&handle_set, SIGHUP);

    /* Start dedicated signal thread */
    pthread_t sig_tid;
    pthread_create(&sig_tid, NULL, signal_thread, &handle_set);

    /* Start worker threads (inherit blocked mask) */
    pthread_t workers[2];
    int ids[] = {1, 2};
    for (int i = 0; i < 2; i++)
        pthread_create(&workers[i], NULL, worker_thread, &ids[i]);

    printf("pid=%d, press Ctrl+C to stop\n", getpid());

    /* Wait for workers */
    for (int i = 0; i < 2; i++)
        pthread_join(workers[i], NULL);
    pthread_join(sig_tid, NULL);

    printf("Clean shutdown complete\n");
    return 0;
}

#include <signal.h>
#include <pthread.h>
#include <stdio.h>

void *sig_thread(void *arg) {
    sigset_t *set = (sigset_t *)arg;
    int sig;
    sigwait(set, &sig);
    printf("Got signal %d\n", sig);
    return NULL;
}

int main(void) {
    sigset_t set;
    sigfillset(&set);
    pthread_sigmask(SIG_BLOCK, &set, NULL);
    pthread_t tid;
    sigset_t wait_set;
    sigemptyset(&wait_set);
    sigaddset(&wait_set, SIGINT);
    pthread_create(&tid, NULL, sig_thread, &wait_set);
    pthread_join(tid, NULL);
    return 0;
}
